for (const src of ['https://cdn.jsdelivr.net/gh/worrydream/Tangle@master/Tangle.js','https://cdn.jsdelivr.net/gh/worrydream/Tangle@master/TangleKit/TangleKit.js']) await new Promise((ok, fail) => { const s = document.createElement('script'); s.src = src; s.onload = ok; s.onerror = fail; document.head.appendChild(s); });
document.getElementById('tangle').appendChild(data.root);
const tangle = new Tangle(data.root, data.model);

